- Silent data loss on buffer overflow
- 100KB is massive for stack frame

## Proposed Fix
```zig
pub fn sendClipboardResponse(self: *Pane, kind: u8, data: []const u8) void {
  const required_size = 9 + data.len;  // ESC ] 52 ; c ; data ESC \
  if (required_size > 100000) {
    log.warn("OSC 52 response too large: {d} bytes", .{required_size});
    return;
  }
  const buf = self.allocator.alloc(u8, required_size) catch return;
  defer self.allocator.free(buf);
  // ... format and send
}
