## Proposed Solution

Create `client/src/hooks/useModalBehavior.ts`:

```typescript
interface UseModalBehaviorOptions {
  isOpen: boolean;
  onClose: () => void;
  closeOnEscape?: boolean;      // default: true
  closeOnOutsideClick?: boolean; // default: false
  preventScroll?: boolean;       // default: true
}

export function useModalBehavior(options: UseModalBehaviorOptions) {
  const {
    isOpen,
    onClose,
    closeOnEscape = true,
    closeOnOutsideClick = false,
    preventScroll = true,
  } = options;

  // Escape key handler
  useEffect(() => {
    if (!closeOnEscape || !isOpen) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        e.preventDefault();
        onClose();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, onClose, closeOnEscape]);

  // Body scroll prevention
  useEffect(() => {
    if (!preventScroll || !isOpen) return;

    const originalOverflow = document.body.style.overflow;
    document.body.style.overflow = 'hidden';

    return () => {
      document.body.style.overflow = originalOverflow;
    };
  }, [isOpen, preventScroll]);

  // Return ref for outside click detection (optional)
  const modalRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!closeOnOutsideClick || !isOpen) return;

    const handleClick = (e: MouseEvent) => {
      if (modalRef.current && !modalRef.current.contains(e.target as Node)) {
        onClose();
      }
    };

    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, [isOpen, onClose, closeOnOutsideClick]);

  return { modalRef };
}
```

**Usage:**
```typescript
function SettingsModal({ isOpen, onClose }) {
  const { modalRef } = useModalBehavior({ isOpen, onClose });

  return (
    <div ref={modalRef} class="modal">
      ...
    </div>
  );
}
```

